FUNCTION H(P, I):
 // This function CANNOT exist
 // Returns 'halts' if program P halts on input I
 // Returns 'loops' if program P runs forever on input I
 // This is undecidable - no such algorithm exists

FUNCTION D(P):
 // Uses H to do the opposite
 result = H(P, P)
 IF result == 'halts' THEN
 LOOP_FOREVER() // Do opposite
 ELSE
 RETURN // halt when H says loops

// The paradox:
// D(D) halts iff H(D,D) says loops
// But H(D,D) says loops iff D(D) halts
// Contradiction! Therefore H cannot exist.

// L is recursive iff there exists TM M that always halts
FUNCTION Decide_M(w):
 // Input: string w
 // Output: ACCEPT or REJECT (must halt)

 // Example: L = {w | w has equal 0s and 1s}
 count0 = 0
 count1 = 0

 FOR each character c in w:
 IF c == '0' THEN count0 = count0 + 1
 IF c == '1' THEN count1 = count1 + 1

 IF count0 == count1 THEN
 RETURN ACCEPT
 ELSE
 RETURN REJECT

// This TM always halts - gives definitive yes/no answer
// Language is RECURSIVE (decidable)

// L is RE (recursively enumerable) iff TM accepts strings in L
// May loop forever on strings not in L
FUNCTION Accept_M(w):
 // Example: L = {⟨M, w⟩ | TM M accepts input w}
 // This is the Acceptance Problem A_TM

 // Simulate M on w
 state = M.start_state
 tape = w
 steps = 0

 WHILE steps < INFINITE:
 // Run M's transition function
 IF M.accepts THEN
 RETURN ACCEPT // Yes - halts and accepts
 IF M.rejects THEN
 RETURN REJECT // Actually, this is never reached for A_TM
 // A_TM may LOOP instead
 steps = steps + 1

 // If we reach here, M loops forever
 // Our TM also loops forever (doesn't halt)
 // This is okay for RE - we just don't give an answer

// This TM is semi-decidable but NOT decidable

// Problem: Given DFA D, is L(D) = ∅?
// This is DECIDABLE

FUNCTION DFA_Empty(D):
 // Use reachability analysis

 // Step 1: Find all reachable states
 reachable = {D.start_state}
 queue = [D.start_state]

 WHILE queue is not empty:
 state = queue.pop()
 FOR each transition state' from state:
 IF state' not in reachable THEN
 reachable.add(state')
 queue.push(state')

 // Step 2: Check if any accepting state is reachable
 FOR each state in reachable:
 IF state in D.accepting_states THEN
 RETURN FALSE // L(D) is NOT empty

 RETURN TRUE // L(D) is empty - no accepting state reachable

// This algorithm ALWAYS halts - DFA emptiness is decidable

// Goal: Show E_TM (emptiness) is undecidable
// Reduction: If E_TM were decidable, then A_TM would be decidable

// Assume we have a decider for E_TM called E
// Construct decider for A_TM:

FUNCTION Decide_A_TM(M, w):
 // Input: TM M and string w
 // Question: Does M accept w?

 // Step 1: Construct new TM M'
 M'.transitions = M.transitions
 M'.start_state = M.start_state

 // Modify M so it ONLY accepts if it would accept w
 ADD new accepting state A
 ADD new non-accepting state R

 FOR each original accepting state of M:
 change to transition to A

 ADD transition from A to A (stay in accepting)

 // M' halts and accepts iff M accepts w
 // M' runs forever (or rejects) otherwise

 // Step 2: Use E (emptiness decider)
 result = E(M') // Is L(M') empty?

 // Step 3: Translate result
 IF result == TRUE THEN
 // L(M') is empty → M does NOT accept w
 RETURN REJECT
 ELSE
 // L(M') is NOT empty → M accepts w
 RETURN ACCEPT

// Since A_TM is undecidable, E_TM must be undecidable
// This is reduction proof technique
